    asset,
    checksumsAsset,
    getRelease
  });
  if (taggedBundle) return taggedBundle;

  const latestBundle = await resolveReleaseAssetBundleFromKind({
    kind: 'latest',
    asset,
    checksumsAsset,
    getRelease
  });
  if (latestBundle) return latestBundle;

  return null;
}

